#ifndef BLOCK_SIZE
#define BLOCK_SIZE 16
#endif

#define AA(_i,_j) a[offset*size+_i*size+_j+offset]
#define BB(_i,_j) a[_i*size+_j]

kernel void lud_diagonal(global float* a, local float* temp, const int size, const int offset)
{
    int i = get_global_id(0);
    int j, k;

    if (i >= BLOCK_SIZE) return;

    // Load diagonal block into local memory
    for (j = 0; j < BLOCK_SIZE; j++) {
        temp[i * BLOCK_SIZE + j] = a[size * (i + offset) + offset + j];
    }
    barrier(CLK_LOCAL_MEM_FENCE);

    // Process diagonal block
    for (i = 0; i < BLOCK_SIZE; i++) {
        for (j = i; j < BLOCK_SIZE; j++) {
            for (k = 0; k < i; k++) {
                temp[i * BLOCK_SIZE + j] = temp[i * BLOCK_SIZE + j] - temp[i * BLOCK_SIZE + k] * temp[k * BLOCK_SIZE + j];
            }
        }

        float temp_val = 1.0f / temp[i * BLOCK_SIZE + i];
        for (j = i + 1; j < BLOCK_SIZE; j++) {
            for (k = 0; k < i; k++) {
                temp[j * BLOCK_SIZE + i] = temp[j * BLOCK_SIZE + i] - temp[j * BLOCK_SIZE + k] * temp[k * BLOCK_SIZE + i];
            }
            temp[j * BLOCK_SIZE + i] = temp[j * BLOCK_SIZE + i] * temp_val;
        }
        barrier(CLK_LOCAL_MEM_FENCE);
    }

    // Write back to global memory
    for (i = 0; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            a[size * (i + offset) + offset + j] = temp[i * BLOCK_SIZE + j];
        }
    }
}

kernel void lud_perimeter(global float* a, local float* temp_top, local float* temp_left, local float* temp_div, const int size, const int offset)
{
    int idx = get_global_id(0);
    int i, j, k;
    float sum;

    if (idx >= BLOCK_SIZE * 2 * ((size - offset) / BLOCK_SIZE - 1)) return;

    int chunk_idx = idx / BLOCK_SIZE;
    int part = idx % BLOCK_SIZE;

    int i_global, j_global;

    if (part < BLOCK_SIZE) {
        // Right perimeter processing
        j_global = offset + BLOCK_SIZE * (chunk_idx + 1);
        i_global = offset;

        // Load temp from diagonal
        for (i = 0; i < BLOCK_SIZE; i++) {
            for (j = 0; j < BLOCK_SIZE; j++) {
                temp_div[i * BLOCK_SIZE + j] = a[size * (i + offset) + offset + j];
            }
        }
        barrier(CLK_LOCAL_MEM_FENCE);

        for (j = 0; j < BLOCK_SIZE; j++) {
            for (i = 0; i < BLOCK_SIZE; i++) {
                sum = 0.0f;
                for (k = 0; k < i; k++) {
                    sum += temp_div[i * BLOCK_SIZE + k] * a[size * (i_global + k) + j_global + j];
                }
                a[size * (i_global + i) + j_global + j] = a[size * (i_global + i) + j_global + j] - sum;
            }
        }
    } else {
        // Bottom perimeter processing
        i_global = offset + BLOCK_SIZE * (chunk_idx + 1);
        j_global = offset;

        // Load temp from diagonal
        for (i = 0; i < BLOCK_SIZE; i++) {
            for (j = 0; j < BLOCK_SIZE; j++) {
                temp_div[i * BLOCK_SIZE + j] = a[size * (i + offset) + offset + j];
            }
        }
        barrier(CLK_LOCAL_MEM_FENCE);

        for (i = 0; i < BLOCK_SIZE; i++) {
            for (j = 0; j < BLOCK_SIZE; j++) {
                sum = 0.0f;
                for (k = 0; k < j; k++) {
                    sum += a[size * (i_global + i) + j_global + k] * temp_div[k * BLOCK_SIZE + j];
                }
                a[size * (i_global + i) + j_global + j] = (a[size * (i_global + i) + j_global + j] - sum) / a[size * (offset + j) + offset + j];
            }
        }
    }
}

kernel void lud_internal(global float* a, local float* temp_top, local float* temp_left, const int size, const int offset)
{
    int i_idx = get_global_id(0);
    int j_idx = get_global_id(1);
    int i, j, k;
    float sum[BLOCK_SIZE];

    int chunks_in_inter_row = (size - offset - BLOCK_SIZE) / BLOCK_SIZE;

    if (i_idx >= chunks_in_inter_row || j_idx >= chunks_in_inter_row) return;

    int i_global = offset + BLOCK_SIZE * (1 + i_idx);
    int j_global = offset + BLOCK_SIZE * (1 + j_idx);

    // Load temp_top and temp_left
    for (i = 0; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            temp_top[i * BLOCK_SIZE + j] = a[size * (i + offset) + j + j_global];
            temp_left[i * BLOCK_SIZE + j] = a[size * (i + i_global) + offset + j];
        }
    }
    barrier(CLK_LOCAL_MEM_FENCE);

    // Initialize sum
    for (j = 0; j < BLOCK_SIZE; j++) {
        sum[j] = 0.0f;
    }

    // Process internal block
    for (i = 0; i < BLOCK_SIZE; i++) {
        for (k = 0; k < BLOCK_SIZE; k++) {
            for (j = 0; j < BLOCK_SIZE; j++) {
                sum[j] += temp_left[BLOCK_SIZE * i + k] * temp_top[BLOCK_SIZE * k + j];
            }
        }
        for (j = 0; j < BLOCK_SIZE; j++) {
            a[size * (i + i_global) + j + j_global] -= sum[j];
            sum[j] = 0.0f;
        }
    }
}
